output.sparql:
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT DISTINCT ?party ?partyLabel ?leader ?leaderLabel WHERE {
  ?party wdt:P31 / wdt:P279 * wd:Q7278 .
  {
    ?party wdt:P17 wd:Q218
  } UNION {
    ?party wdt:P1001 wd:Q218
  }
  .
  OPTIONAL {
    ?party wdt:P1906 | wdt:P488 | wdt:P114 | wdt:P9688 ?leader .
  }
  OPTIONAL {
    ?party rdfs:label ?partyLabel .
    FILTER(LANG(?partyLabel) = 'en' || LANG(?partyLabel) = 'ro')
  }
  OPTIONAL {
    ?leader rdfs:label ?leaderLabel .
    FILTER(LANG(?leaderLabel) = 'en' || LANG(?leaderLabel) = 'ro')
  }
}
